def check_ca_fop_symbol_present_on_exempt_product(product: dict) -> str | None:
    """
    Returns the rule tag if all three fields are present, numeric, and greater than 0.0.
    Otherwise returns None.
    """
    tag = "ca-fop-symbol-present-on-exempt-product"
    required_fields = ["fop_symbol_present", "fop_exempt_proxy", "product_is_prepackaged_proxy"]

    for field in required_fields:
        if field not in product:
            return None
        value = product[field]
        # Treat None as missing
        if value is None:
            return None
        # Ensure numeric (exclude bool)
        if isinstance(value, bool) or not isinstance(value, (int, float)):
            return None
        if not (value > 0.0):
            return None

    return tag

